INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1248, 190273, 5, 1404, '孤独的等待', '心情很差，也许是你退还戒指给我，买了条黑线把它戴起来一直看到它的缘故吧。其实我真的很想跟你说我对你真的用心的，为什么你一直不相信我呢，为什么一直说我是在骗你呢？生日那天我在路上看到.....可我为什么还在深渊里爬不起来，其实我每天都在问自己为什么会这样为什么会这样，可是一直找不到答案。前几天我帮朋友去借高利贷，还帮他支付月利息.我看到他有急用而真的不想看到他在象我以前一样，而他门现在是两个人我是自己一个人没有什么好顾虑的所以就。。。因为我始终记得曾诺这两个字的重量，只知道我对曾诺的话会算数的，不管是以前还是现在，永远都会这样的', '心情很差，也许是你退还戒指给我，买了条黑线把它戴起来一直看到它的缘故吧。其实我真的很想跟你说我对你真的用心的，为什么你一直不相信我呢，为什么一直说我是在骗你呢？生日那天我在路上看到.....可我为什么还在深渊里爬不起来，其实我每天都在问自己为什么会这样为什么会这样，可是一直找不到答案。前几天我帮朋友去借高利贷，还帮他支付月利息.我看到他有急用而真的不想看到他在象我以前一样，而他门现在是两个人我是自己一个人没有什么好顾虑的所以就。。。因为我始终记得曾诺这两个字的重量，只知道我对曾诺的话会算数的，不管是以前还是现在，永远都会这样的', NULL, '2002-11-30 16:14:00', 0, '20021230100509_bbsid_190273_board_5_1197d7cef1.html', '20021230100509');
